<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Matrix Rain Background</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            min-height: 100vh;
            font-family: 'Courier New', monospace;
            overflow: hidden;
            position: relative;
            background: #000;
        }

        /* Matrix Rain Background */
        .matrix-bg {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: -1;
            overflow: hidden;
            pointer-events: none;
        }

        .matrix-bg canvas {
            display: block;
        }

        /* Overlay for better text readability */
        .overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(3px);
            z-index: 0;
        }

        .content {
            position: relative;
            z-index: 1;
            padding: 2rem;
            color: #00ff41;
            text-align: center;
        }

        h1 {
            font-size: 4rem;
            margin-bottom: 1rem;
            text-shadow: 0 0 10px #00ff41, 0 0 20px #00ff41;
            font-family: 'Courier New', monospace;
            animation: text-fade 3s ease-in-out infinite alternate;
        }

        p {
            font-size: 1.2rem;
            opacity: 0.9;
            font-family: 'Courier New', monospace;
        }

        @keyframes text-fade {
            from {
                opacity: 0.8;
            }
            to {
                opacity: 1;
            }
        }

        /* CRT scanline effect */
        .crt-lines {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: repeating-linear-gradient(
                0deg,
                rgba(0, 0, 0, 0.15),
                rgba(0, 0, 0, 0.15) 1px,
                transparent 1px,
                transparent 2px
            );
            pointer-events: none;
            z-index: 10;
        }

        /* Vignette effect */
        .vignette {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: radial-gradient(
                circle, 
                transparent 50%,
                rgba(0, 0, 0, 0.8) 100%
            );
            pointer-events: none;
            z-index: 11;
        }
    </style>
</head>
<body>
    <div class="gradient-bg"></div>
    <div class="overlay"></div>
    <div class="content">
        <h1>🌈 Dynamic Gradient Background</h1>
        <p>Smooth color transitions with continuous animation</p>
    </div>

    <script>
        // Advanced gradient animation with dynamic color generation
        class GradientAnimation {
            constructor() {
                this.colors = [];
                this.currentHue = 0;
                this.hueSpeed = 0.5;
                this.gradientElement = document.querySelector('.gradient-bg');
                this.init();
            }

            init() {
                // Generate a vibrant color palette
                this.colors = [
                    '#1a1a2e', '#16213e', '#0f3460',
                    '#533483', '#6c5ce7', '#a29bfe',
                    '#fd79a8', '#fdcb6e', '#e17055',
                    '#00b894', '#0984e3', '#6c5ce7',
                    '#ff7675', '#74b9ff', '#55efc4',
                    '#ffeaa7', '#fab1a0', '#a29bfe'
                ];

                // Apply initial gradient
                this.updateGradient();

                // Start animation
                this.animate();
            }

            // Generate HSL color string
            hslToRgb(h, s, l) {
                s /= 100;
                l /= 100;
                const k = n => (n + h / 30) % 12;
                const a = s * l * Math.min(k(3), k(9), k(15) - 1);
                const b = s * l * Math.min(k(3) - 1, k(9), 1);
                const c = s * l * Math.min(k(9) - 1, k(15), k(3));
                const m = l - s * l;

                return [
                    Math.round(m + a),
                    Math.round(m + b),
                    Math.round(m + c)
                ].join(', ');
            }

            updateGradient() {
                const gradient = `linear-gradient(
                    ${this.currentHue}deg,
                    hsl(${this.currentHue}, 60%, 20%),
                    hsl(${(this.currentHue + 40) % 360}, 60%, 20%),
                    hsl(${(this.currentHue + 80) % 360}, 60%, 20%),
                    hsl(${(this.currentHue + 120) % 360}, 60%, 20%),
                    hsl(${(this.currentHue + 160) % 360}, 60%, 20%)
                )`;
                this.gradientElement.style.background = gradient;
            }

            animate() {
                this.currentHue = (this.currentHue + this.hueSpeed) % 360;
                this.updateGradient();
                requestAnimationFrame(() => this.animate());
            }
        }

        // Initialize the gradient animation
        document.addEventListener('DOMContentLoaded', () => {
            new GradientAnimation();

            // Add interactive effect on mouse movement
            document.addEventListener('mousemove', (e) => {
                const x = e.clientX / window.innerWidth;
                const y = e.clientY / window.innerHeight;

                // Subtle parallax effect
                const gradient = document.querySelector('.gradient-bg');
                gradient.style.backgroundPosition = `${x * 20}% ${y * 20}%`;
            });
        });
    </script>
</body>
</html>
